import 'package:flutter/material.dart';
import 'package:pooja_sindhu/core/theme/app_colors.dart';
import 'package:pooja_sindhu/core/theme/app_spacing.dart';
class AppSecondaryButton extends StatelessWidget { const AppSecondaryButton({super.key, required this.label, this.onPressed, this.isLoading = false, this.fullWidth = true}); final String label; final VoidCallback? onPressed; final bool isLoading; final bool fullWidth; @override Widget build(BuildContext context) { final button = OutlinedButton(onPressed: isLoading ? null : onPressed, style: OutlinedButton.styleFrom(foregroundColor: AppColors.primary, side: const BorderSide(color: AppColors.primary), minimumSize: const Size(48, 52), padding: const EdgeInsets.symmetric(horizontal: AppSpacing.xl, vertical: AppSpacing.md)), child: isLoading ? const SizedBox(width: 20, height: 20, child: CircularProgressIndicator(strokeWidth: 2)) : Text(label)); return fullWidth ? SizedBox(width: double.infinity, child: button) : button; } }
